import tippy, { followCursor } from "tippy.js";
import "tippy.js/dist/tippy.css";
import "tippy.js/animations/perspective.css";
// import "tippy.js/animations/scale.css";

export function initScrollToTop() {
  const el = document.querySelector("#back-to-top-link");
  if (!el) return;
  window.addEventListener("scroll", () => {
    if (window.scrollY > 300) {
      el.classList.add("show");
    } else {
      el.classList.remove("show");
    }
  });
}

export function initTableOfContents() {
  const containers = document.querySelectorAll("#toc");

  [...containers].forEach((container) => {
    if (container.innerHTML) return;
    const twoLevels = container.getAttribute("data-two-levels");
    const allHeadings = document.querySelectorAll(
      twoLevels ? "main h2, main h3" : "main h2",
    );
    if (allHeadings.length < 2) return;
    let output = "<b>Table of Contents:</b><ul>";
    if (container.closest("aside")) {
      output += `<li><a href="#">(Top)</a></li>`;
    }
    let isFirst = true;
    [...allHeadings].forEach((headingEl) => {
      const title = headingEl.innerHTML
        .replaceAll("<b>", "")
        .replaceAll("</b>", "");
      const link =
        headingEl.getAttribute("id") ||
        encodeURI(
          title
            .replaceAll("(Optional)", "")
            .replaceAll(" ", "-")
            .replaceAll(":", "")
            .replaceAll("#", "")
            .replaceAll(".", "")
            .replaceAll("(", "")
            .replaceAll(")", "")
            .replaceAll('"', "")
            .replaceAll("&amp;", "")
            .replaceAll(/<[^>]*>?/gm, "")
            .replace(/-$/, "")
            .replaceAll("--", "-"),
        ).toLowerCase();
      headingEl.setAttribute("id", link);
      const isH2 = headingEl.tagName == "H2";
      if (twoLevels && isH2) {
        if (!isFirst) output += `</ul></li>`;
        output += `
	  <li><a href="#${link}">${title}</a>
	  <ul>`;
      } else {
        output += `
	  <li><a href="#${link}">${title}</a></li>`;
      }
      isFirst = false;
    });
    container.innerHTML = output + "</ul>";
  });

  initSidebarTableOfContents();
}

function initSidebarTableOfContents() {
  const el = document.querySelector(".coding-page-layout .aside #toc");
  if (!el) return;
  const allSections = document.querySelectorAll("main section h2");

  updateSidebarTableOfContentsPosition(el, allSections);

  // debounced: https://www.onlywebpro.com/tutorials/javascript/optimize-scrolling-performance-by-debouncing-scroll-event-calls
  let debounce_timer;
  window.addEventListener("scroll", function () {
    if (debounce_timer) {
      window.clearTimeout(debounce_timer);
    }
    debounce_timer = window.setTimeout(function () {
      updateSidebarTableOfContentsPosition(el, allSections);
    }, 20);
  });
}

function updateSidebarTableOfContentsPosition(el, allSections) {
  const minPixelInViewport = 200;
  const cutOff = document
    .querySelector("#toc-position")
    .getBoundingClientRect().top;

  if (cutOff < 0) {
    el.classList.add("fixed-toc");
  } else {
    el.classList.remove("fixed-toc");
  }

  // Current section
  [...allSections].forEach((section) => {
    const theId = section.getAttribute("id");
    const theTocElement = el
      .querySelector('[href="#' + theId + '"]')
      .closest("li");
    const theSection = section.closest("section");
    const theSectionRect = theSection.getBoundingClientRect();
    const sectionIsInViewport =
      theSectionRect.bottom >= minPixelInViewport &&
      theSectionRect.top + minPixelInViewport <=
        (window.innerHeight || document.documentElement.clientHeight);

    if (sectionIsInViewport) {
      theTocElement.classList.add("active");
    } else {
      theTocElement.classList.remove("active");
    }
  });
}

export function initTooltips() {
  tippy("*:not(iframe)[title]", {
    plugins: [followCursor],
    arrow: true,
    placement: "top", // top, right, bottom, left
    delay: 5, //ms
    distance: 25, //px or string
    maxWidth: 300, //px or string
    followCursor: true,
    allowHTML: true,
    theme: "custom",
    ignoreAttributes: true,
    animation: "perspective",
    // animation: "scale",
    // inertia: true,
    content(reference) {
      const title = reference.getAttribute("title");
      reference.removeAttribute("title");
      return title;
    },
  });
}

export function initProgressBar() {
  const progressBar = document.querySelector(".progress-bar");
  if (!progressBar) return;

  progressBar.style.width = 1 + "%";

  const buyMeCoffeeHeight = document.querySelector(".buy-me-a-coffee")
    ? document.querySelector(".buy-me-a-coffee").getBoundingClientRect().height
    : 0;
  const commentSectionHeight = document.querySelector(
    ".buy-me-a-coffee + section",
  )
    ? document
        .querySelector(".buy-me-a-coffee + section")
        .getBoundingClientRect().height
    : 0;

  window.addEventListener("scroll", function () {
    if (window.scrollY > 800) {
      document.querySelector(".progress-bar-container").classList.add("show");
    } else {
      document
        .querySelector(".progress-bar-container")
        .classList.remove("show");
    }

    const scroll = document.documentElement.scrollTop;
    const height =
      document.documentElement.scrollHeight -
      document.documentElement.clientHeight -
      buyMeCoffeeHeight -
      commentSectionHeight;
    let scrolled = (scroll / height) * 100;
    if (scrolled > 100) scrolled = 100;

    document.querySelector(".progress-bar-percent").innerHTML =
      Math.round(scrolled);

    if (scrolled <= 1) {
      progressBar.style.width = 1 + "%";
    } else if (scrolled >= 2 && scrolled <= 99.9) {
      progressBar.style.width = scrolled + "%";
      progressBar.classList.remove("progress-bar--100");
    } else if (scrolled === 100) {
      progressBar.style.width = scrolled + "%";
      progressBar.classList.add("progress-bar--100");
    }
  });
}

export function initActiveLinks() {
  const pathname = window.location.pathname.replace("/public", "");

  const els = document.querySelectorAll(
    ".aside-nav li a, .coding-navigation li a",
  );
  [...els].forEach((el) => {
    const href = el
      .getAttribute("href")
      .replace(".html", "")
      .replace("/public", "");

    if (href == pathname) {
      el.classList.add("active");
      if (el.closest(".aside-nav details, .coding-navigation-category")) {
        el.closest(
          ".aside-nav details, .coding-navigation-category",
        ).setAttribute("open", "open");
        el.closest(
          ".aside-nav details, .coding-navigation-category",
        ).classList.add("active");
      }
    }
  });

  // Bearblog
  if (isFromHere()) {
    const bearBlogLinks = document.querySelectorAll("[href='/bearblog']");
    bearBlogLinks.forEach((link) => {
      link.style.display = "none";
    });
  }

  // Special pages
  const codingHelpMenu = document.querySelector(
    ".aside-nav details#menu-codinghelp",
  );
  if (!codingHelpMenu) return;
  if (
    pathname.includes("neocities-external-widgets") ||
    pathname.includes("neocities-automatic-deployment")
  ) {
    codingHelpMenu.setAttribute("open", "open");
    codingHelpMenu.classList.add("active");
    document.querySelector("#menu-more").removeAttribute("open");
    document.querySelector("#menu-more .active").classList.remove("active");
  }
}

function isFromHere() {
  const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
  return timezone == "Europe/Berlin" || timezone == "Europe/Vienna";
}

export function initToggleExplanationComments() {
  const inputEl = document.querySelector("#explanation-toggle");
  if (!inputEl) return;
  inputEl.checked = true;
  inputEl.addEventListener("change", () => {
    const isChecked = event.currentTarget.checked;
    if (!isChecked) {
      document.querySelector("#hide-explanation").style.display = "block";
      document.querySelector("#show-explanation").style.display = "none";
    } else {
      document.querySelector("#hide-explanation").style.display = "none";
      document.querySelector("#show-explanation").style.display = "block";
    }
  });
}

export function initLinkPreviews() {
  if (screen.width < 500) return;
  const linkEls = document.querySelectorAll("a[href].activate-preview");
  linkEls.forEach((linkEl) => {
    // if (!linkEl.style.position || linkEl.style.position == "static")
    //   linkEl.style.position = "relative";
    let previewEl = document.createElement("div");
    previewEl.classList.add("preview-frame");
    previewEl.innerHTML = `<iframe></iframe>`;

    linkEl.addEventListener("mouseenter", () => {
      const thisPreviewEl = linkEl.querySelector(".preview-frame");
      if (!thisPreviewEl) {
        linkEl.appendChild(previewEl);
        const iFrameEl = previewEl.querySelector("iframe");
        iFrameEl.setAttribute("src", linkEl.getAttribute("href"));
        previewEl.classList.add("preview-frame--visible");
        previewEl.classList.add("preview-frame--loading");

        setTimeout(() => {
          previewEl.classList.remove("preview-frame--loading");
        }, 2000);
        iFrameEl.onload = () => {
          previewEl.classList.remove("preview-frame--loading");
        };

        iFrameEl.onerror = () => {
          iFrameEl.setAttribute("src", "");
          previewEl.classList.remove("preview-frame--visible");
        };
      } else {
        thisPreviewEl.classList.add("preview-frame--visible");
      }
    });

    linkEl.addEventListener("mouseleave", () => {
      const thisPreviewEl = linkEl.querySelector(".preview-frame");
      if (thisPreviewEl)
        thisPreviewEl.classList.remove("preview-frame--visible");
    });
  });
}

