export function initChristmas() {
  const currentMonth = new Date().getMonth() + 1;
  const isAdventCalendarPage = document.querySelector("#advent-calendar");
  if (!isAdventCalendarPage && currentMonth != 12) return; // only in december

  // CSS
  document.head.appendChild(document.createElement("style")).innerHTML = `
#santa-hat {
  position: absolute;
  transform: scaleX(-1) scale(0.6);
  top: -40px;
  left: -10px;
  filter: contrast(0.95) saturate(0.8);


}

@media (max-width: 1105px) {
  #santa-hat {
    display: none;
  }
}

@media (max-width: $sm) {
  #santa-hat {
    display: inline;
  }
}

body::after {
  content: "";
  position: fixed;
  bottom: 0;
  left: 0;
  right: 0;
  background: white;
  background: linear-gradient(0deg, rgba(255, 255, 255, 1) 0%, rgba(255, 255, 255, 0) 100%);
  height: 50px;
  z-index: 9999;
  pointer-events: none;
}

body.dark-mode::after {
  display: none;
}

`;

  // FALLING SNOW
  /* https://embed.im/snow */
  var embedimSnow = document.getElementById("embedim--snow");
  if (!embedimSnow) {
    function embRand(a, b) {
      return Math.floor(Math.random() * (b - a + 1)) + a;
    }
    var embCSS =
      ".embedim-snow{position: absolute;width: 9px;height: 9px;background: white;border-radius: 50%;margin-top:-10px}";
    var embHTML = "";
    var i = 1;
    for (i = 1; i < 200; i++) {
      embHTML += '<i class="embedim-snow"></i>';
      var rndX = embRand(0, 1000000) * 0.0001,
        rndO = embRand(-100000, 100000) * 0.0001,
        rndT = (embRand(3, 8) * 10).toFixed(2),
        rndS = (embRand(0, 10000) * 0.0001).toFixed(2);
      embCSS +=
        ".embedim-snow:nth-child(" +
        i +
        "){" +
        "opacity:" +
        (embRand(1, 10000) * 0.0001).toFixed(2) +
        ";" +
        "transform:translate(" +
        rndX.toFixed(2) +
        "vw,-10px) scale(" +
        rndS +
        ");" +
        "animation:fall-" +
        i +
        " " +
        embRand(10, 30) +
        "s -" +
        embRand(0, 30) +
        "s linear infinite" +
        "}" +
        "@keyframes fall-" +
        i +
        "{" +
        rndT +
        "%{" +
        "transform:translate(" +
        (rndX + rndO).toFixed(2) +
        "vw," +
        rndT +
        "vh) scale(" +
        rndS +
        ")" +
        "}" +
        "to{" +
        "transform:translate(" +
        (rndX + rndO / 2).toFixed(2) +
        "vw, 105vh) scale(" +
        rndS +
        ")" +
        "}" +
        "}";
    }
    embedimSnow = document.createElement("div");
    embedimSnow.id = "embedim--snow";
    embedimSnow.innerHTML =
      "<style>#embedim--snow{position:fixed;left:0;top:0;bottom:0;width:100vw;height:100vh;overflow:hidden;z-index:9999999;pointer-events:none}" +
      embCSS +
      "</style>" +
      embHTML;
    document.body.appendChild(embedimSnow);
  }
}

export function initAprilFools() {
  const today = new Date();
  const offset = today.getTimezoneOffset();
  const today2 = new Date(today.getTime() - offset * 60 * 1000);
  const day = today2.toISOString().split("T")[0];
  if (day == "2026-04-01") {
    document.body.style.transform = "scaleY(-1)";
    document.title = "APRIL FOOLS !!!";
  }
}
